import pickle

class PreferenceObject:
    def __init__(self, data):
        self.__dict__.update(data)

    def dump(self, filename):
        with open(filename, 'wb') as f:
            pickle.dump(self, f)

    @staticmethod
    def load(filename):
        with open(filename, 'rb') as f:
            return pickle.load(f)